// Gather all pages of deals + contacts, dedupe company ids, emit one item per
// batch of <=100 company ids for the batch-read call (plus one 'empty' item if none).
const deals=$('Get deals (all pages)').all().flatMap(i=>(i.json.results||[]));
const contacts=$('Get contacts (all pages)').all().flatMap(i=>(i.json.results||[]));
const compAssoc=o=>{const a=((o.associations||{}).companies||{}).results||[];return a.length?String(a[0].id):null;};
const ids=new Set();
for(const o of deals.concat(contacts)){const id=compAssoc(o);if(id)ids.add(id);}
const all=[...ids];
const batches=[];
for(let i=0;i<all.length;i+=100)batches.push(all.slice(i,i+100));
if(!batches.length)batches.push([]);
return batches.map(b=>({json:{inputs:b.map(id=>({id}))}}));

// Build ONE idempotent upsert for stakeholders + deals.
// Company names come from the batch reads (may be empty if the token lacks the
// companies scope - the deal-name prefix fallback still resolves most accounts).
const q=s=>(s===null||s===undefined||s==='')?'NULL':"'"+String(s).replace(/'/g,"''")+"'";
const num=v=>{if(v===null||v===undefined||v==='')return 'NULL';const n=Number(v);return isNaN(n)?'NULL':String(n);};

// stage-id -> label map from the pipelines call
const stageMap={};const pipeMap={};
for(const p of ($('Get pipelines').first().json.results||[])){pipeMap[p.id]=p.label;for(const s of (p.stages||[])){stageMap[s.id]=s.label;}}

// company id -> {name,domain}
const comp={};
for(const it of $('Read companies (batch)').all()){for(const c of (it.json.results||[])){comp[String(c.id)]={name:(c.properties||{}).name||null,domain:(c.properties||{}).domain||null};}}

const compAssoc=o=>{const a=((o.associations||{}).companies||{}).results||[];return a.length?String(a[0].id):null;};
const CLOSED=/closed won|closed lost|qualified out/i;

const dealRows=[];
for(const it of $('Get deals (all pages)').all()){for(const d of (it.json.results||[])){
  const p=d.properties||{};const cid=compAssoc(d);const cname=cid&&comp[cid]?comp[cid].name:null;
  const stage=stageMap[p.dealstage]||p.dealstage||null;
  const isOpen=stage?(!CLOSED.test(stage)):true;
  dealRows.push('('+q(d.id)+','+q(p.dealname)+','+num(p.amount)+','+q(pipeMap[p.pipeline]||p.pipeline)+','+q(stage)+','+(isOpen?'true':'false')+','+num(p.networks_score)+','+q(p.closedate)+'::timestamptz,'+q(cid)+','+q(cname)+')');
}}

const stakRows=[];
for(const it of $('Get contacts (all pages)').all()){for(const c of (it.json.results||[])){
  const p=c.properties||{};const cid=compAssoc(c);const cname=cid&&comp[cid]?comp[cid].name:null;
  const name=((p.firstname||'')+' '+(p.lastname||'')).trim();
  if(!name)continue;
  stakRows.push('('+q(c.id)+','+q(name)+','+q(p.email)+','+q(p.jobtitle)+','+q(p.hs_buying_role)+','+q(p.hs_seniority)+','+q(cid)+','+q(cname)+')');
}}

const parts=[];
if(dealRows.length){parts.push(
  "INSERT INTO deals (hubspot_deal_id,name,amount,pipeline,stage,is_open,networks_score,close_date,hubspot_company_id,company_name,account_id,last_verified) "+
  "SELECT v.hid,v.nm,v.amt,v.pipe,v.stage,v.open,v.nscore,v.close,v.cid,v.cname,"+
  "COALESCE("+
  "(SELECT id FROM accounts WHERE v.cname IS NOT NULL AND (lower(name)=lower(v.cname) OR v.cname ILIKE '%'||name||'%' OR name ILIKE '%'||v.cname||'%') ORDER BY length(name) DESC LIMIT 1),"+
  "(SELECT id FROM accounts WHERE split_part(v.nm,' - ',1) ILIKE '%'||name||'%' OR name ILIKE '%'||split_part(v.nm,' - ',1)||'%' ORDER BY length(name) DESC LIMIT 1)"+
  "), now() "+
  "FROM (VALUES "+dealRows.join(',')+") AS v(hid,nm,amt,pipe,stage,open,nscore,close,cid,cname) "+
  "ON CONFLICT (hubspot_deal_id) DO UPDATE SET name=EXCLUDED.name, amount=EXCLUDED.amount, pipeline=EXCLUDED.pipeline, stage=EXCLUDED.stage, is_open=EXCLUDED.is_open, networks_score=EXCLUDED.networks_score, close_date=EXCLUDED.close_date, company_name=COALESCE(EXCLUDED.company_name, deals.company_name), account_id=COALESCE(EXCLUDED.account_id, deals.account_id), last_verified=now();");}
if(stakRows.length){parts.push(
  "INSERT INTO stakeholders (hubspot_contact_id,name,email,job_title,buying_role,seniority,hubspot_company_id,company_name,account_id,last_verified) "+
  "SELECT v.hid,v.nm,v.em,v.jt,v.br,v.sen,v.cid,v.cname,"+
  "(SELECT id FROM accounts WHERE v.cname IS NOT NULL AND (lower(name)=lower(v.cname) OR v.cname ILIKE '%'||name||'%' OR name ILIKE '%'||v.cname||'%') ORDER BY length(name) DESC LIMIT 1), now() "+
  "FROM (VALUES "+stakRows.join(',')+") AS v(hid,nm,em,jt,br,sen,cid,cname) "+
  "ON CONFLICT (hubspot_contact_id) DO UPDATE SET name=EXCLUDED.name, email=EXCLUDED.email, job_title=EXCLUDED.job_title, buying_role=EXCLUDED.buying_role, seniority=EXCLUDED.seniority, company_name=COALESCE(EXCLUDED.company_name, stakeholders.company_name), account_id=COALESCE(EXCLUDED.account_id, stakeholders.account_id), last_verified=now();");}
// Client-name directory from HubSpot (Monday decommissioned): company names +
// deal-name prefixes ('HMRC - Dynamo' -> HMRC) keep the Watcher's account matching alive.
const dirNames=new Set();
for(const k in comp){const nm=(comp[k].name||'').trim();if(nm)dirNames.add(nm);}
for(const it of $('Get deals (all pages)').all()){for(const dd of (it.json.results||[])){const pre=String((dd.properties||{}).dealname||'').split(' - ')[0].trim();if(pre.length>=2&&pre.length<=40)dirNames.add(pre);}}
if(dirNames.size){parts.push("INSERT INTO client_directory (name,source,last_seen) VALUES "+[...dirNames].map(n=>'('+q(n)+",'hubspot',now())").join(',')+" ON CONFLICT (name) DO UPDATE SET last_seen=now();");}
if(!parts.length)parts.push("SELECT 'nothing to sync' AS note;");
return [{json:{sql:parts.join(' '),deals:dealRows.length,stakeholders:stakRows.length,companies:Object.keys(comp).length}}];
